	var env, snd;
	env = EnvGen.kr(Env.linen(0, decay, 0), doneAction: 2);
	snd = Pluck.ar(
		in: PinkNoise.ar(hit),
		trig: Impulse.kr(0),
		maxdelaytime: 0.1,
		delaytime: freq.reciprocal,
		decaytime: decay,
		coef: coef);
	snd = Pan2.ar(snd,pan,amp);
	snd = GVerb.ar(snd,34,0.55,0.25,0.27,55,1,0.25,0.2);
	snd = LeakDC.ar(snd).clip2;
	Out.ar(out, snd * env);
}).add;

