    var relaxOsc = LFPulse.ar(lfo, width: 0.9, mul: toneAmp);

    var asr = EnvGen.kr(Env.asr(atkTime * 5, releaseTime: 0.001, curve: \lin), gate: trigger);

    Out.ar(0, relaxOsc * asr)
}).add
)

