//self-similar sloth-canon routine, for some integer a, r(n) = r(a*n)
(
r = Routine({
	var seed = #[0,1,0], i=0, temp, temp2 = List[], out;
	temp = seed;
    loop {
		out = temp[((i/3).floor)%temp.size] + seed[i%seed.size];
		if(i%9 == 0, {out.post}); //comment next line and uncomment this line to demonstrate that for seed [0,1,0], r(n) = r(3*n) for all n
		//out.post;
        0.1.wait;
		i = i+1;
		temp2.add(out);
		if((i+1) > (temp.size**2), {temp = temp2});
    }
});
)
