(//disperser taken from https://scsynth.org/t/phase-rotation-fos/5575
SynthDef(\simpleSaw, {
	arg root=150, oTone=1, uTone=1, amp=0.8, gate = 0.5, release = 1, k= 0.4, curve = 2, lag = 0.01;
	var sig, finalFreq, env, tempO, tempU, sigL, sigR, sigM, sigS, hornbostelwertheimerkonstante = 0.00063;
	tempO = oTone;
	tempU = uTone;
	oTone = oTone.max(1);
	uTone = uTone.max(1);
	finalFreq = (oTone/uTone) * root;
	finalFreq = finalFreq.lag2(lag);
	sig = Saw.ar(finalFreq, 0.5);
	sig =sig *(tempO.abs.min(1))*(tempU.abs.min(1));//mutes notes with oTone or uTone = to 0
	sigL = DelayC.ar(sig, 1, LFNoise1.ar(1.11, finalFreq * hornbostelwertheimerkonstante * 0.005));
	sigR = DelayC.ar(sig, 1, LFNoise1.ar(1.1, finalFreq * hornbostelwertheimerkonstante * 0.005));
	sigM = sigL + sigR;
	sigS = sigL - sigR;
	100.do {sigS = FOS.ar(sigS, k.neg, 1, k);}; //allpass disperser
	sigL = (sigM + sigS);
	sigR =  (sigM - sigS);
	sig = [sigL, sigR];
	env = EnvGen.kr(Env.adsr(0.01, 0, 1, release, 1, curve), gate, levelScale: 1, doneAction: Done.freeSelf);
	sig = sig*env;
	Out.ar(0, sig!2);
}).add;
)

