(
SynthDef(\kick808, { arg out=0, amp=0.7, gate=1;
    var sig, env, freq;
    env = EnvGen.kr(Env.perc(0.001, 0.5), gate, doneAction: 2);
    freq = EnvGen.kr(Env([180, 60, 40], [0.02, 0.3], \exp));
    sig = SinOsc.ar(freq) * env * amp;
    sig = sig.tanh;
    Out.ar(out, Pan2.ar(sig, 0));
}).add;

SynthDef(\snare808, { arg out=0, amp=0.5, gate=1;
    var sig, env, tone, noise;
    env = EnvGen.kr(Env.perc(0.001, 0.18), gate, doneAction: 2);
    tone = SinOsc.ar([200, 320]).sum * 0.3;
    noise = HPF.ar(WhiteNoise.ar(0.7), 1000);
    sig = (tone + noise) * env * amp;
    Out.ar(out, Pan2.ar(sig, 0));
}).add;

SynthDef(\hh808, { arg out=0, amp=0.3, gate=1;
    var sig, env;
    env = EnvGen.kr(Env.perc(0.001, 0.06), gate, doneAction: 2);
    sig = HPF.ar(WhiteNoise.ar, 7000) * env * amp;
    Out.ar(out, Pan2.ar(sig, 0));
}).add;
)

