// Live-Aenderungen: einfach den String editieren und den Pdef-Block
// neu evaluieren (Ctrl+Enter). Pattern springt zum naechsten Bar-Wechsel
// nahtlos um.
//
// === Variations-Ideen ===
//
// Trap-Style Hihat:
//   ~xox.("xxxxxxxxxxxxxxxx") fuer 16tel, dann manche Steps double-time
//
// Off-Beat Kick:
//   ~xox.("oxxooxxo") fuer "Klassik Disco"
//
// Aksak (5er): ~xox.("xoxox") laesst sich auch in 5-Step-Frame nutzen
//   weil dur einfach den Step verlaengert/verkuerzt
//
// === Beziehung zu Euklidisch ===
//
// XoX und Euklidisch (Pbjorklund / .euclid in Strudel) loesen die gleiche
// Aufgabe unterschiedlich:
// - Euklidisch: "3 Pulse auf 8 Steps" → Algorithmus verteilt automatisch
// - XoX: "xxooxoox" → ich notiere jeden Step direkt
//
// Vorteil XoX: 100% explizit, jeder Step sichtbar
// Vorteil Euklidisch: kompakter, gut fuer ungewohnte Verhaeltnisse (7,12)
//
// Beide nebeneinander in einem Track ist normal.

(
~xox = {|str| str.collectAs({|l| switch(l.toLower,$x, {1}, $o, {Rest(1)})}, Array)};
)


(
SynthDef(\acid, { arg out, freq = 1000, gate = 1, pan = 1, cut = 4000, rez = 0.8, amp = 1, sustain = 1, release = 0.5;
    var sig, env;
	env = EnvGen.kr(Env.linen(0.01, sustain, sustain * release), gate, amp, doneAction: Done.freeSelf);
	sig = Pulse.ar([freq,freq*1.001], 0.5);
	sig = sig + Pulse.ar(freq*0.501, 0.01, [0,0.5]);
	sig = sig + Pulse.ar(freq*1.99, 0.11, [0.5,0]);
	sig = RLPF.ar(sig, cut, rez);
	sig = Pan2.ar(sig);
	sig = sig * env;

	Out.ar(out, sig);
}).add;
)

